def main():
    '\nDuring inheritance, the constructor (__init__) of the parent class is not automatically called;\nit must be called explicitly if the child class defines its own constructor.\n\nMRO is the order in which Python looks for a method in a hierarchy of classes.\n\nIt follows the depth-first, left-to-right rule.\n\n__init__ method resolution follows MRO; the first __init__ found in the MRO chain will be executed.\n'

    class A:

        def __init__(self):
            print('A __init__')

    class B(A):

        def __init__(self):
            print('B __init__')
            super().__init__()

    class C(A):

        def __init__(self):
            print('C __init__')
            super().__init__()

    class D(B, C):

        def __init__(self):
            print('D __init__')
            super().__init__()

    d = D()

if __name__ == "__main__":
    main()
